function hasValidCustomSource() {
    const value = (source.getLoginInfoMap())['自定义源站'];
    return !(value == null || value == undefined || value == "" || String(value).trim() == "");
}

function showCustomSourceAlert() {
    const customSource = (source.getLoginInfoMap())['自定义源站'];
    java.toast(
        "\n⚠️ 自定义源站配置提醒 ⚠️\n" +
        "──────────────────\n" +
        "检测到已设置自定义源站: \n✨" +
        "【" + (customSource || "") + "】✨\n" +
        "──────────────────\n" +
        "请前往「书源登录」清除配置\n" +
        "才能使指定源站切换生效"
    );
}

function login(){
    const loginInfo = source.getLoginInfoMap();
    const email = loginInfo['邮箱'];
    const password = loginInfo['密码'];

    if (!email || !password) {
        java.toast("\n❌ 请先填写账号和密码并点击✓保存后登录");
        return;
    }

    java.toast("正在登录...");
    const host = getServerHost();
    const url = host + '/login';
    const body = "email=" + encodeURIComponent(email) + "&password=" + encodeURIComponent(password);

    try {
        const response = java.ajax(url + "," + JSON.stringify({
            method: "POST",
            body: body,
            timeout: 10000
        }));

        const result = JSON.parse(response);

        if (result.code == 200) {
            const user = result.data.user;
            const apiKey = user.api_key;
            const isMember = user.is_member || false;

            source.putLoginHeader(apiKey);

            const nickname = user.nickname || "用户";
            const maskedEmail = email.includes('@') ? 
                email.substring(0, 3) + "****" + email.substring(email.indexOf('@')) : 
                email;

            const memberStatus = isMember ? "👑尊贵VIP会员" : "普通会员";
            const welcomeMsg = isMember ? "欢迎回来，👑尊贵VIP会员" : "欢迎回来";

            java.toast(
                "\n───────────────\n" +
                "🌟 " + welcomeMsg + " 🌟\n" +
                "───────────────\n" +
                "昵称：" + nickname + "\n" +
                "邮箱：" + maskedEmail + "\n" +
                "状态：" + memberStatus + "\n" +
                "───────────────"
            );
        } else {
            const errorCode = result.code || "未知";
            const errorMessage = result.message || "未知错误";

            java.toast(
                "\n───────────────\n" +
                "❌ 登录失败 ❌\n" +
                "───────────────\n" +
                "错误代码：" + errorCode + "\n" +
                "错误信息：" + errorMessage + "\n" +
                "───────────────"
            );
        }

    } catch (e) {
        java.toast(
            "\n───────────────\n" +
            "❌ 网络错误 ❌\n" +
            "───────────────\n" +
            "连接服务器失败\n" +
            "请检查网络连接\n" +
            "───────────────"
        );
    }
}

function user_logout() {
    let hadLogin = false;

    if (source.getLoginHeader() && String(source.getLoginHeader()).trim().length > 0) {
        hadLogin = true;
    }

    source.putLoginHeader("");

    if (!source.getLoginHeader() || String(source.getLoginHeader()).trim().length === 0) {
        java.toast(hadLogin ? "\n❗ 已成功退出登录" : "\nℹ️ 当前未登录状态");
    }
}

function updateConfig(key, value, message, gender) {
    if (key == "source" && hasValidCustomSource()) {
        showCustomSourceAlert();
        return;
    }

    try {
        var config = JSON.parse(source.getVariable());
        if (!config || !Array.isArray(config) || config.length === 0) {
            config = [{}];
        }
        config[0][key] = value;
        if (gender !== undefined) {
            config[0]["gender"] = gender;
        }
        source.setVariable(JSON.stringify(config));
        java.toast(message || "设置已更新");
    } catch(e) {
        var newConfig = {[key]: value};
        if (gender !== undefined) {
            newConfig["gender"] = gender;
        }
        source.setVariable(JSON.stringify([newConfig]));
        java.toast(message || "初始化设置");
    }
}

