function createHtml(JsonData,t){
    let html = "";
    for(i in JsonData){
        let x = JsonData[i];
        let replyHtml = "";
        if(x.l2Count && x.l2Count >0){
            let openReply = \` <div class="load-more-replies" data-id="$\{x.id}" data-num="0">≚ 共$\{x.l2Count}条回复 还剩$\{x.l2Count}条</div>\`;

            replyHtml = \`<div class="replies-section">
                $\{openReply}
            </div>\`
        }

        if(x.title){
            html += '<div class="title">'+x.title+'</div>';
            continue;
        }
        let user_badges = "";
        if(x.author || x.authorFeedBack){
        user_badges = \`<div class="user-badges">
                    <div class="badge gold">
                          $\{x.author || x.authorFeedBack}
                    </div>
                </div>\`
        }

        let quote =  x.quote?\`<div class="comment-quote">$\{x.quote}</div>\`:"";
        let info = \`<div class="comment-info">
                            <div class="comment-meta">$\{x.meta.replace(/•$/,'')}</div>$\{quote}
                            <div class="comment-actions">
                                <div class="action-btn"><i class="far fa-thumbs-up"></i> $\{x.agreenum}</div>
                       </div>
                    </div>\`;

        html+=\`<div class="$\{t}-item">
                    <div class="$\{t}-header">
                         <div class="username" data-id="$\{x.blogId}">$\{x.username}</div>
                         $\{user_badges}
                    </div>
                    <div class="comment-content">$\{replaceemotes(x.content,x.emotes)}</div>
                    <div class="comment-pic">$\{x.pics}</div>
                    $\{info}
                    $\{replyHtml}
                </div>\`
    };

    if(t=="comment"){
        if(html==""){
            html = \`<div style="text-align: center;
        padding: 10px;
        color: #666;
        font-size: 14px;">暂无评论</div>\`
        }
    }
    return html
}


  function checkScrollBottom() {
    if (isLoading || !hasMore) return;
    const lastComment = document.querySelector('.comment-item:last-of-type');
    if (!lastComment) return;
    const windowHeight = window.innerHeight;
    const documentHeight = document.documentElement.scrollHeight;
    const scrollTop = window.scrollY || document.documentElement.scrollTop;
    if (documentHeight - (scrollTop + windowHeight) < 100) {
        loadNextPage();
    }
}

function loadNextPage() {
    if (isLoading || !hasMore) return;
    let offset = contentJson.data.offset;
    if (offset < 0) { 
                hasMore = false;
                const noMore = document.createElement('div');
                noMore.className = 'no-more';
                noMore.textContent = '没有更多评论了';
                noMore.style.cssText = \`
                    text-align: center;
                    padding: 10px;
                    color: #999;
                    font-size: 14px;
                \`;
                document.querySelector('.comments-container')?.appendChild(noMore);
                return;
    }
    page++;
    isLoading = true;
    const loader = document.createElement('div');
    loader.className = 'loading-more';
    loader.textContent = '加载 第'+page+'页 中...';
    loader.style.cssText = \`
        text-align: center;
        padding: 10px;
        color: #666;
        font-size: 14px;
    \`;

    const container = document.querySelector('.comments-container') || document.body;
    container.appendChild(loader);
    setTimeout(() => {
        fetchMoreComments()
            .then(() => {
                container.removeChild(loader);
                isLoading = false;
            })
            .catch(() => {
                loader.textContent = '加载失败，点击重试';
                loader.style.color = '#f00';
                loader.onclick = () => {
                    container.removeChild(loader);
                    isLoading = false;
                    page--;
                    loadUrl();
                };
            });
    }, 100);
}  


 function fetchMoreComments() {
    return new Promise((resolve) => {
        setTimeout(() => {
            let offset = contentJson.data.offset;
            currentUrl = currentUrl.replace(/offset=\\d+/,"offset="+offset);
            var htmlString = createCommentHtml(getJson(currentUrl));
            const container = document.querySelector('.comments-container') || document.body;
            const loader = container.querySelector('.loading-more');
            if (loader) {
                loader.insertAdjacentHTML('beforebegin', htmlString);
             } else {
                 container.insertAdjacentHTML('beforeend', htmlString);
             }
             openReply()
            resolve();
        }, 1000);
    });
} 



 let scrollTimer;
window.addEventListener('scroll', function() {
    clearTimeout(scrollTimer);
    scrollTimer = setTimeout(checkScrollBottom, 100);
});




