        data = JsonData.data;
        upmid = data.upper.mid;
        if(t!==2)
        offset = data.cursor.pagination_reply.next_offset;


        if(data.root && replyPage ==1){
            data.top_replies = [];
            data.root.rcount = 0;
            pageTotal = data.page.count;
            data.top_replies.push(data.root)
        }

        r.commentTotal = data?.cursor?.all_count;
        allReplys = data.top_replies?data.top_replies.concat(data.replies):data.replies;
    }


    for(i in allReplys){
        let x = allReplys[i];
        let comment = {};

        comment.meta =  x.reply_control.time_desc+(x.reply_control.up_reply?"•UP主回复":"");

        comment.content = parseContent(x.content.message,x.content.pictures,x.content.emote,x.content.at_name_to_mid,x.content.jump_url);
        comment.username = x.member.uname;
        comment.agreenum = x.like;
        let top = x.reply_control.is_up_top?"置顶":""
        if(top)comment.top = top;
        comment.authorid = upmid;
        comment.isAuthor = x.member.mid==upmid;
        comment.readerid = x.member.mid;
        comment.icon = x.member.nameplate.image ?? "";
        comment.rate = "LV"+x.member.level_info.current_level;
        comment.replyNum = Number(x.rcount) ?? 0;
        comment.id = x.rpid;
        comment.author_agree= x.reply_control.up_like;
        if(comment.replyNum>0){
            comment.list = x.replies?getJson(x.replies,1,upmid):[];
        }
        commentList.push(comment)
    }

    if(t==1)return commentList;

    r.list = commentList;
    return r

}     

 function parseContent(content,pics,emo,atname,jump_url){
     if(emo){
