                   key.replace(/[.*+?^$\{}()|[\\]\\\\]/g, '\\\\$&')
         );
         emok2.forEach((x,i)=>{
             let re = new RegExp(x,'g');
            content = content.replace(re,"<img src=\\""+emo[emok[i]].url+"\\" class=\\"emote\\">")
         })
      }

      if(atname){
          let atnamek = Object.keys(atname);
          let atname2 = atnamek.map(key => 
                   key.replace(/[.*+?^$\{}()|[\\]\\\\]/g, '\\\\$&')
         );

         atname2.forEach((x,i)=>{
             let re = new RegExp("@"+x,'g');
            content = content.replace(re,"<span class=\\"atname\\" data-readerid=\\""+atname[atnamek[i]]+"\\">@"+atnamek[i]+"</span>")
         })
      }


      if(jump_url){
          let jump_urlk = Object.keys(jump_url);
          let jump_url2 = jump_urlk.map(key => 
                   key.replace(/[.*+?^$\{}()|[\\]\\\\]/g, '\\\\$&')
         );

         jump_url2.forEach((x,i)=>{
             let re = new RegExp(x,'g');
             let aid =/^\\d+$/.test(jump_url[jump_urlk[i]].click_report)?jump_url[jump_urlk[i]].click_report:jump_urlk[i];
             let type = /^\\d+$/.test(aid)?"🎥":(/^http/.test(aid)?"🔗":"🔎");
            content = content.replace(re,"<span class=\\"jump_url\\" data-aid=\\""+aid+"\\">"+type+jump_url[jump_urlk[i]].title+"</span>")
         })
      }
    let imgs = "";

    if(pics && pics.length > 0){
