        // 初始化
        document.addEventListener('DOMContentLoaded', () => {
            initTheme();
            initSortButtons();

            // 隐藏底部输入栏，使用顶部评论按钮
            document.body.style.paddingBottom = '20px';

            document.getElementById('commentTextarea').addEventListener('input', updateCharCount);

            initEmojiPanel(); // 初始化表情面板
            initInfiniteScroll();
            loadComments();
        });

        function initTheme() {
            let readerSettings = localStorage.getItem('readerSettings');
            let theme = localStorage.getItem('theme');
            if (readerSettings) {
                try {
                    const parsed = JSON.parse(readerSettings);
                    if (parsed.theme !== undefined) {
                        theme = parsed.theme;
                    }
                } catch {}
            }

            // 设置默认值为auto
            if (!theme) {
                theme = 'auto';
                localStorage.setItem('theme', 'auto');
            }

            updateTheme(theme);
        }

        function updateTheme(theme) {
            const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
            let isDark;

            if (theme === 'auto') {
                isDark = prefersDark;
            } else {
                isDark = theme === 'dark';
            }

            if (isDark) {
                document.documentElement.classList.add('dark');
                document.body.classList.add('dark');
            } else {
                document.documentElement.classList.remove('dark');
                document.body.classList.remove('dark');
            }

            updateThemeIcon(theme);
        }

        function updateThemeIcon(theme) {
            const icon = document.getElementById('themeIcon');

            if (theme === 'auto') {
                icon.className = 'fas fa-adjust';
            } else if (theme === 'dark') {
                icon.className = 'fas fa-sun';
            } else {
                icon.className = 'fas fa-moon';
            }
        }

        function toggleTheme() {
            let currentTheme = localStorage.getItem('theme');
            let newTheme;

            if (currentTheme === 'auto') {
                // From auto to opposite of current system preference
                const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
                newTheme = prefersDark ? 'light' : 'dark';
            } else if (currentTheme === 'light') {
                newTheme = 'dark';
            } else {
                newTheme = 'auto';
            }

            localStorage.setItem('theme', newTheme);
            updateTheme(newTheme);
        }

        // Listen for system theme changes in auto mode
        window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', (e) => {
            const currentTheme = localStorage.getItem('theme');
            if (currentTheme === 'auto') {
                updateTheme('auto');
            }
        });

        function initInfiniteScroll() {
            let scrollTimeout;
            let lastScrollTime = 0;

            window.addEventListener('scroll', () => {
                const now = Date.now();
                if (now - lastScrollTime < 100) return; // 节流，100ms内不重复处理
                lastScrollTime = now;

                clearTimeout(scrollTimeout);
                scrollTimeout = setTimeout(() => {
                    if (config.isLoading || !config.hasMore) return;

                    const scrollTop = document.documentElement.scrollTop || document.body.scrollTop;
                    const windowHeight = window.innerHeight;
                    const documentHeight = document.documentElement.scrollHeight;
                    const distance = documentHeight - (scrollTop + windowHeight);

                    // 增加触发距离，避免过早加载
                    if (distance < 100 && distance > -50) {
                        loadComments();
                    }
                }, 150); // 防抖，150ms后执行
            }, { passive: true });
        }

        function initSortButtons() {
            const sortByHot = document.getElementById('sortByHot');
            if (config.source === '七猫') {
                sortByHot.innerHTML = '<i class="fas fa-history"></i> 最早';
            }
        }

        function initEmojiPanel() {
            const emojiGrid = document.getElementById('emojiGrid');
            if (!emojiGrid) return;

            Object.entries(emojiMap).forEach(([text, src]) => {
                const btn = document.createElement('button');
                btn.type = 'button';
                btn.className = 'emoji-btn';
                btn.innerHTML = \`<img src="\${src}" alt="\${text}">\`;
                btn.onclick = (e) => {
                    e.preventDefault();
                    e.stopPropagation();
                    insertEmoji(text);
                };
                emojiGrid.appendChild(btn);
            });
        }

        function toggleEmojiPanel(e) {
            e.preventDefault();
            e.stopPropagation();
            document.getElementById('emojiPanel').classList.toggle('show');
        }

        function insertEmoji(text) {
            const textarea = document.getElementById('commentTextarea');
            const start = textarea.selectionStart;
            const end = textarea.selectionEnd;
            const textBefore = textarea.value.substring(0, start);
            const textAfter = textarea.value.substring(end);
            textarea.value = textBefore + text + textAfter;
            textarea.focus();
            textarea.selectionStart = textarea.selectionEnd = start + text.length;
            updateCharCount();
            document.getElementById('emojiPanel').classList.remove('show');
        }

        function sortComments(sortType) {
            if (config.currentSort === sortType) return;
            config.currentSort = sortType;

            document.querySelectorAll('.sort-btn').forEach(btn => btn.classList.remove('active'));
            if (sortType === 'time') {
                document.getElementById('sortByTime').classList.add('active');
            } else {
                document.getElementById('sortByHot').classList.add('active');
            }

            let sortedComments = [...config.allComments];

            if (config.source === '七猫') {
                if (sortType === 'hot') {
                    sortedComments.reverse();
                }
            } else {
                if (sortType === 'hot') {
                    sortedComments.sort((a, b) => (b.like_count || 0) - (a.like_count || 0));
                } else {
                    sortedComments.sort((a, b) => (b.create_timestamp || 0) - (a.create_timestamp || 0));
                }
            }

            config.comments = sortedComments;
            renderComments(sortedComments, false);
        }

        async function loadComments(retryCount = 0) {
            if (config.isLoading) return;

            // 预检查：如果已经确定没有更多数据，直接返回
            if (!config.cursor && config.comments.length > 0) {
                console.log('没有更多数据可加载（cursor为空）');
                return;
            }

            // 如果已经有大量数据但cursor为空，认为已经加载完毕
            if (!config.cursor && config.comments.length > 20) {
                console.log('数据量充足且cursor为空，停止加载');
                config.hasMore = false;
                return;
            }

            config.isLoading = true;

            const isFirstLoad = !config.cursor;
            if (!isFirstLoad) {
                document.getElementById('noMore').classList.add('hidden');
                showLoadingMore(true);
            }

            try {
                let url = \`${baser_url}/para_review?book_id=\${config.bookId}&item_id=\${config.itemId}&para=\${config.currentPara}&source=\${encodeURIComponent(config.source)}\`;

                if (config.cursor) {
                    url += \`&cursor=\${encodeURIComponent(config.cursor)}\`;
                }

                // 添加超时控制
                const controller = new AbortController();
                const timeoutId = setTimeout(() => controller.abort(), 10000); // 10秒超时

                const response = await fetch(url, {
                    signal: controller.signal,
                    headers: {
                        'Accept': 'application/json',
                        'Content-Type': 'application/json'
                    }
                });

                clearTimeout(timeoutId);

                if (!response.ok) {
                    throw new Error(\`HTTP \${response.status}: \${response.statusText}\`);
                }

                const result = await response.json();

                document.getElementById('loading').classList.add('hidden');
                showLoadingMore(false);

                if (result.code === 0 && result.data) {
                    const data = result.data;

                    if (isFirstLoad) {
                        // 修复：如果 total 为 0 但实际有评论，使用评论数组长度
                        const commentCount = data.total || 
                            (data.comments?.length || 0) + (data.hot_comments?.length || 0);
                        document.getElementById('headerTitle').textContent = commentCount > 0 
                            ? \`\${commentCount}条评论\` 
                            : '评论';
                    }

                    if (isFirstLoad && data.paragraph_content) {
                        const paraEl = document.getElementById('paragraphQuote');
                        paraEl.textContent = data.paragraph_content.length > 100 
                            ? data.paragraph_content.substring(0, 100) + '...' 
                            : data.paragraph_content;
                        paraEl.classList.remove('hidden');
                    }

                    if (isFirstLoad && data.hot_comments && data.hot_comments.length > 0) {
                        config.hotComments = data.hot_comments;
                        renderHotComments(data.hot_comments);
                        document.getElementById('hotSection').classList.remove('hidden');
                        document.getElementById('moreSection').classList.remove('hidden');
                        document.getElementById('moreCount').textContent = \`(\${data.total || 0})\`;
                    }

                    // 处理评论数据（包括空数据情况）
                    const comments = data.comments || [];
                    if (comments.length > 0) {
                        if (isFirstLoad) {
                            config.allComments = [...comments];
                            config.comments = [...comments];
                            renderComments(comments, false);
                        } else {
                            config.allComments = config.allComments.concat(comments);
                            config.comments = config.comments.concat(comments);
                            renderComments(comments, true);
                        }
                    }

                    // 更严谨的状态判断
                    const hasMoreFromServer = data.has_more;
                    const nextCursor = data.next_cursor || '';

                    // 如果服务器明确返回hasMore=false，或者没有下一页游标且当前页数据为空，则停止加载
                    config.hasMore = hasMoreFromServer === true && nextCursor !== '' && comments.length > 0;

                    // 特殊情况：如果服务器返回hasMore=true但没有数据，可能是后端bug，保守处理
                    if (hasMoreFromServer === true && comments.length === 0) {
                        console.warn('服务器返回hasMore=true但没有数据，停止加载以避免死循环');
                        config.hasMore = false;
                    }

                    config.lastCursor = config.cursor; // 保存上一个cursor
                    config.cursor = nextCursor;

                    // 调试日志
                    console.log(\`加载完成: 当前页\${comments.length}条, hasMore=\${config.hasMore}, cursor='\${config.cursor}'\`);

                    if (!config.hasMore && config.comments.length > 0) {
                        document.getElementById('noMore').classList.remove('hidden');
                        console.log('已到达最后一页，停止加载更多');
                    }

                    if (config.comments.length === 0 && config.hotComments.length === 0) {
                        document.getElementById('empty').classList.remove('hidden');
                    }
                } else {
                    if (isFirstLoad) {
                        document.getElementById('empty').classList.remove('hidden');
                    }
                }
            } catch (error) {
                console.error('加载评论失败:', error);
                document.getElementById('loading').classList.add('hidden');
                showLoadingMore(false);

                // 更详细的错误处理
                let errorMsg = '加载失败，请重试';
                if (error.name === 'AbortError') {
                    errorMsg = '请求超时，请检查网络后重试';
                } else if (error.message.includes('HTTP')) {
                    errorMsg = '服务器错误，请稍后重试';
                } else if (error.message.includes('Failed to fetch')) {
                    errorMsg = '网络连接失败，请检查网络';
                }

                showToast(errorMsg);

                // 重置cursor，允许重试
                if (!isFirstLoad) {
                    config.cursor = config.lastCursor || '';
                }

                // 自动重试机制
                if (retryCount < config.maxRetryCount && !isFirstLoad) {
                    const retryDelay = Math.min(1000 * Math.pow(2, retryCount), 5000); // 指数退避，最大5秒
                    console.log(\`加载失败，\${retryDelay/1000}秒后重试(\${retryCount + 1}/\${config.maxRetryCount})\`);

                    setTimeout(() => {
                        loadComments(retryCount + 1);
                    }, retryDelay);

                    // 显示重试提示
                    showToast(\`加载失败，\${retryDelay/1000}秒后自动重试\`);
                    return; // 不重置isLoading，让重试逻辑处理
                }
            } finally {
                config.isLoading = false;
            }
        }

        function showLoadingMore(show) {
            let loadingMore = document.getElementById('loadingMore');
            if (!loadingMore) {
                loadingMore = document.createElement('div');
                loadingMore.id = 'loadingMore';
                loadingMore.className = 'loading';
                loadingMore.style.padding = '20px';
                loadingMore.style.opacity = '0';
                loadingMore.style.transition = 'opacity 0.3s ease';
                loadingMore.innerHTML = '<div class="loading-spinner" style="width:24px;height:24px;margin-bottom:8px;"></div><span style="font-size:13px;">加载更多...</span>';
                document.querySelector('.main-container').appendChild(loadingMore);

                // 强制重排后添加动画
                setTimeout(() => {
                    loadingMore.style.opacity = '1';
                }, 10);
            }

            if (show) {
                loadingMore.style.display = 'flex';
                setTimeout(() => {
                    loadingMore.style.opacity = '1';
                }, 10);
            } else {
                loadingMore.style.opacity = '0';
                setTimeout(() => {
                    loadingMore.style.display = 'none';
                }, 300);
            }
        }

        function renderHotComments(comments) {
            const container = document.getElementById('hotCommentList');
            container.innerHTML = '';
            document.getElementById('hotCount').textContent = \`(\${comments.length})\`;

            comments.forEach(comment => {
                container.appendChild(createCommentElement(comment, 'hot'));
            });
        }

        function renderComments(comments, append = false) {
            const container = document.getElementById('commentList');
            if (!append) {
                container.innerHTML = '';
            }

            comments.forEach(comment => {
                container.appendChild(createCommentElement(comment, 'normal'));
            });
        }

        function createCommentElement(comment, type) {
            const div = document.createElement('div');
            div.className = 'comment-item';
            div.dataset.commentId = comment.comment_id;

            // 用户标签
            let tagsHtml = '';
            if (comment.user && comment.user.is_author) {
                tagsHtml += '<span class="comment-tag tag-author">作者</span>';
            }
            if (comment.user && comment.user.is_vip) {
                tagsHtml += '<span class="comment-tag tag-vip">VIP</span>';
            }
            if (comment.user && comment.user.tags) {
                comment.user.tags.forEach(tag => {
                    tagsHtml += \`<span class="comment-tag tag-custom">\${tag}</span>\`;
                });
            }

            // 图片
            let imageHtml = '';
            if (comment.image_url) {
                imageHtml = \`<img class="comment-image" src="\${comment.image_url}" onclick="openImagePreview('\${comment.image_url}')" alt="" onerror="this.style.display='none'">\`;
            }

            // 展开回复逻辑
            let expandHtml = '';
            let replyListHtml = '';

            const inlineReplyCount = (comment.replies && comment.replies.length) || 0;
            const serverReplyCount = comment.reply_count || 0;

            // 只有当有回复时才显示展开按钮
            if (serverReplyCount > 0 || inlineReplyCount > 0) {
                const uniqueId = \`\${type}-\${comment.comment_id}\`;
                const totalReplies = Math.max(serverReplyCount, inlineReplyCount);

                // 七猫：始终从接口获取回复（内嵌回复只是预览）
                if (config.source === '七猫') {
                    expandHtml = \`
                        <div class="expand-replies" onclick="toggleReplies('\${uniqueId}', '\${comment.comment_id}')">
                            展开\${totalReplies}条回复
                            <i class="fas fa-chevron-down"></i>
                        </div>
                    \`;
                    replyListHtml = \`<div class="reply-list" id="replies-\${uniqueId}"></div>\`;
                } else if (inlineReplyCount > 0) {
                    // 番茄/塔读：有内嵌回复，默认收起，标记已加载
                    replyListHtml = \`<div class="reply-list" id="replies-\${uniqueId}" data-loaded="true">\${renderRepliesHtml(comment.replies)}</div>\`;
                    expandHtml = \`
                        <div class="expand-replies" onclick="toggleReplies('\${uniqueId}', '\${comment.comment_id}')">
                            展开\${totalReplies}条回复
                            <i class="fas fa-chevron-down"></i>
                        </div>
                    \`;
                } else {
                    // 没有内嵌回复，需要从接口加载
                    expandHtml = \`
                        <div class="expand-replies" onclick="toggleReplies('\${uniqueId}', '\${comment.comment_id}')">
                            展开\${totalReplies}条回复
                            <i class="fas fa-chevron-down"></i>
                        </div>
                    \`;
                    replyListHtml = \`<div class="reply-list" id="replies-\${uniqueId}"></div>\`;
                }
            }

            // 头像
            const userName = comment.user?.user_name || '匿名用户';
            const userAvatar = comment.user?.user_avatar || '';
            const avatarHtml = userAvatar 
                ? \`<img src="\${userAvatar}" alt="" onerror="this.style.visibility='hidden'">\`
                : \`<div class="default-avatar"><i class="fas fa-user"></i></div>\`;

            div.innerHTML = \`
                <div class="comment-main">
                    <div class="comment-avatar">
                        \${avatarHtml}
                    </div>
                    <div class="comment-body">
                        <div class="comment-header">
                            <span class="comment-username">\${userName}</span>
                            \${tagsHtml}
                        </div>
                        <div class="comment-content">\${convertEmoji(comment.content || '')}</div>
                        \${imageHtml}
                        <div class="comment-footer">
                            <div class="comment-meta">
                                <span class="comment-time">\${comment.create_time || ''}</span>
                                \${config.source === '番茄' ? '<span class="comment-reply-btn" style="display:none;">回复</span>' : ''}
                            </div>
                            <div class="comment-likes">
                                <i class="far fa-heart"></i>
                                <span>\${comment.like_count || 0}</span>
                            </div>
                        </div>
                    </div>
                </div>
                \${expandHtml}
                \${replyListHtml}
            \`;

            return div;
        }

        function renderRepliesHtml(replies) {
            if (!replies || replies.length === 0) return '';

            return replies.map(reply => {
                let replyToHtml = '';
                if (reply.reply_to_user && reply.reply_to_user.user_name) {
                    replyToHtml = \`
                        <span class="reply-to">回复</span>
                        <span class="reply-to-username">\${reply.reply_to_user.user_name}</span>
                    \`;
                }

                let tagsHtml = '';
                if (reply.user && reply.user.is_author) {
                    tagsHtml += '<span class="comment-tag tag-author" style="margin-left:6px;">作者</span>';
                }

                const userName = reply.user?.user_name || '匿名';
                const userAvatar = reply.user?.user_avatar || '';
                const avatarHtml = userAvatar 
                    ? \`<img src="\${userAvatar}" alt="" onerror="this.style.visibility='hidden'">\`
                    : \`<div class="default-avatar small"><i class="fas fa-user"></i></div>\`;

                return \`
                    <div class="reply-item">
                        <div class="reply-main">
                            <div class="reply-avatar">
                                \${avatarHtml}
                            </div>
                            <div class="reply-body">
                                <div class="reply-header">
                                    <span class="reply-username">\${userName}</span>
                                    \${tagsHtml}
                                    \${replyToHtml}
                                </div>
                                <div class="reply-content">\${convertEmoji(reply.content || '')}</div>
                                <div class="reply-footer">
                                    <span class="reply-time">\${reply.create_time || ''}</span>
                                    <div class="reply-likes">
                                        <i class="far fa-heart"></i>
                                        <span>\${reply.like_count || 0}</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                \`;
            }).join('');
        }

        async function toggleReplies(uniqueId, commentId) {
            const container = document.getElementById(\`replies-\${uniqueId}\`);
            const expandLink = document.querySelector(\`[onclick*="toggleReplies('\${uniqueId}'"]\`);
            const isExpanded = container.classList.contains('show');

            if (isExpanded) {
                // 收起
                container.classList.remove('show');
                const replyCount = container.querySelectorAll('.reply-item').length;
                expandLink.innerHTML = \`展开\${replyCount}条回复 <i class="fas fa-chevron-down"></i>\`;
                expandLink.classList.remove('expanded');
            } else {
                // 展开
                if (container.dataset.loaded === 'true') {
                    // 已有数据，直接显示
                    container.classList.add('show');
                    expandLink.innerHTML = '收起回复 <i class="fas fa-chevron-down"></i>';
                    expandLink.classList.add('expanded');
                } else {
                    // 需要加载
                    expandLink.innerHTML = '加载中... <i class="fas fa-spinner fa-spin"></i>';
                    container.classList.add('show');

                    try {
                        const url = \`${baser_url}/para_review?book_id=\${config.bookId}&item_id=\${config.itemId}&comment_id=\${commentId}&source=\${encodeURIComponent(config.source)}\`;
                        const response = await fetch(url);
                        const result = await response.json();

                        if (result.code === 0 && result.data && result.data.replies && result.data.replies.length > 0) {
                            container.innerHTML = renderRepliesHtml(result.data.replies);
                            container.dataset.loaded = 'true';
                            expandLink.innerHTML = '收起回复 <i class="fas fa-chevron-down"></i>';
                            expandLink.classList.add('expanded');
                        } else {
                            container.innerHTML = '<div style="padding:16px;color:#999;font-size:13px;text-align:center;">暂无回复</div>';
                            container.dataset.loaded = 'true';
                            expandLink.innerHTML = '收起 <i class="fas fa-chevron-down"></i>';
                            expandLink.classList.add('expanded');
                        }
                    } catch (error) {
                        console.error('加载回复失败:', error);
                        container.innerHTML = '<div style="padding:16px;color:#ff4d4f;font-size:13px;text-align:center;">加载失败，点击重试</div>';
                        container.classList.remove('show');
                        expandLink.innerHTML = '展开回复 <i class="fas fa-chevron-down"></i>';
                    }
                }
            }
        }

        function convertEmoji(text) {
                    if (!text) return '';
            Object.entries(emojiMap).forEach(([key, src]) => {
                const regex = new RegExp(key.replace(/[.*+?^\${}()|[\\]\\\\]/g, '\\\\$&'), 'g');
                text = text.replace(regex, \`<img src="\${src}" class="bq" alt="\${key}">\`);
            });
            return text;
        }

        function openCommentModal() {
            if (config.source !== '番茄') {
                showToast('当前平台暂不支持评论');
                return;
            }
            document.getElementById('commentModal').classList.add('show');
            document.getElementById('commentTextarea').focus();
        }

        function closeCommentModal(event) {
            if (event && event.target !== document.getElementById('commentModal')) return;
            document.getElementById('commentModal').classList.remove('show');
            document.getElementById('emojiPanel').classList.remove('show');
        }

        function updateCharCount() {
            const textarea = document.getElementById('commentTextarea');
            const charCount = document.getElementById('charCount');
            const length = textarea.value.length;
            charCount.textContent = \`\${length}/500\`;
            charCount.classList.toggle('over', length > 500);
        }

        async function submitComment() {
            const content = document.getElementById('commentTextarea').value.trim();
            if (!content) {
                showToast('请输入评论内容');
                return;
            }
            if (content.length > 500) {
                showToast('评论内容不能超过500字');
                return;
            }

            try {
                const url = \`${baser_url}/post_idea_review?ssionid=\${config.ssionid}\`;
                const response = await fetch(url, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        text: content,
                        book_id: config.bookId,
                        item_id: config.itemId,
                        para: config.currentPara,
                        para_content: content
                    })
                });
                const result = await response.json();

                if (result.code === 0) {
                    showToast('发表成功');
                    closeCommentModal();
                    document.getElementById('commentTextarea').value = '';
                    updateCharCount();
                    config.cursor = '';
                    config.allComments = [];
                    config.comments = [];
                    config.hotComments = [];
                    loadComments();
                } else {
                    showToast(result.msg || '发表失败');
                }
            } catch (error) {
                console.error('发表评论失败:', error);
                showToast('发表失败，请重试');
            }
        }

        function openImagePreview(url) {
            document.getElementById('previewImage').src = url;
            document.getElementById('imagePreview').classList.add('show');
        }

        function closeImagePreview() {
            document.getElementById('imagePreview').classList.remove('show');
        }

        function showToast(message) {
            const toast = document.getElementById('toast');
            toast.textContent = message;
            toast.classList.add('show');
            setTimeout(() => toast.classList.remove('show'), 2000);
        }
    </script>
</body>
</html>`
}


//按钮切换时改变源变量并刷新发现
function show(m, t) {
    const {
        java,
        source
    } = this;
    //源变量为空时刷新发现，重置源变量
    source.getVariable()==''?java.refreshExplore():'';//
    var data = JSON.parse(source.getVariable());
    //java.log(data);
    data[t] = m;
    //java.log(JSON.stringify(data));
    source.setVariable(JSON.stringify(data, null, 2));
    java.refreshExplore();
}

/**
 * 创建筛选器配置
 * @param {string} title - 筛选器标题
 * @param {string[]} chars - 选项列表
 * @param {string} defaultVal - 默认值
 * @param {string} paramKey - URL参数名
 * @param {number} size - 布局占比（0-1之间，如0.33表示33%）
 * @returns {Object} 筛选器配置对象
 */
function createFilter(title, chars, defaultVal, paramKey, size) {
    return {
        title: title,
        type: "select",
        chars: chars,
        default: defaultVal,
        action: `show(infoMap['${title}'],'${paramKey}')`,
        style: {
            layout_flexGrow: 1,
            layout_flexBasisPercent: size
        }
    };
}

