function set_media(media) {
    const mediaConfig = {
        '喜马拉雅': ['听书'],
        '番茄': '*',
        '福利小说': ['小说'],
        '如漫画': ['漫画'],
        '包子漫画': ['漫画'],
        '九妖漫画': ['漫画'],
        '绅士漫画': ['漫画'],
        '福利漫画': ['漫画'],
