loginUrl:
Url();

function getUrl() {
    try {
        let urls = Array.from(org.jsoup.Jsoup.parse(java.get("https://www.manwake.cc/", {}).body()).select('.btnBox a'), x => x.attr('href'));
        if (urls.length === 0) throw new Error('未获取到站源');
        let data = JSON.parse(source.getVariable());
        data.Urls = urls;
        source.setVariable(JSON.stringify(data, null, "\t"));
        java.toast(`获取到${urls.length}个站源\n${urls.join('\n')}`);
    } catch (e) {
        java.log(e.message)
        java.toast('获取失败，请检查网络');
    }
}

function setUrl(n) {
    let data = JSON.parse(source.getVariable());
    if (n + 1 > data.Urls.length) return java.toast(`暂时没有站源${n + 1}`);
    data.sourceurl = data.Urls[n];
    try {
    	  let ty = java.get(data.Urls[n], {});
    	  if(!ty.body().includes('漫蛙')) throw new Error('站源失效');
    	} catch (e) {
    		 java.log(e)
    		 java.toast("\n当前站源已失效，请切换其他站源!");
    		 return;
    		}
    source.setVariable(JSON.stringify(data, null, "\t"));
    java.toast(`当前站源已切换到：\n${data.Urls[n]}`);
}

function login() {}

function Login() {
    let username = String(result?.["用户名"]) || "axb";
    let password = String(result?.["密码"]) || "123456789@";
    let url = `${Url()}/api/user/login`;
    try {
        let response = JSON.parse(java.post(url, JSON.stringify({
            username,
            password
        }), {
            "x-requested-with": "XMLHttpRequest",
            "Content-Type": "application/json"
        }).body());
        if (!/successful/.test(response.msg)) return java.toast(response.msg);
        let token = response.data.token;
        source.putLoginHeader(JSON.stringify({
            "Authorization": "Bearer " + token,
            "Cookie": "authToken=" + token
        }));
        result["用户名"] = username;
        result["密码"] = password;
        source.putLoginInfo(JSON.stringify(result));
        java.toast(`\n用户：${username}\n登录成功！`);
    } catch (e) {
        java.log(e.message);
        java.toast('请求失败，请检查网络状况！');
    }
}

function LoginOut() {
    source.removeLoginHeader();
    cookie.removeCookie(Url());
    java.toast('登出成功！');
}

function register() {
    let infoData = generateRandomInfo();
    let username = infoData.username;
    let email = infoData.email;
    let password = infoData.password;
    let url = `${Url()}/api/user/register`;
    const captchaResponse = JSON.parse(java.get(`${Url()}/api/user/captcha`, {}).body());

    let body = JSON.stringify({
        username,
        password,
        email,
        nickname: username,
        captchaId: captchaResponse.captchaId,
        captchaCode: java.getVerificationCode(captchaResponse.img)
    });
    try {
        let response = JSON.parse(java.post(url, body, {
            "x-requested-with": "XMLHttpRequest",
            "Content-Type": "application/json"
        }).body());
        if (!/successful/.test(response.msg)) return java.toast(response.msg);
        java.log(`\n用户名：${username}\n注册邮箱：${email}\n密码：${password}`);
        let token = response.data.token;
        result["用户名"] = username;
        result["密码"] = password;
        source.putLoginInfo(JSON.stringify(result));
        source.putLoginHeader(JSON.stringify({
            "Authorization": "Bearer " + token,
            "Cookie": "authToken=" + token
        }));
        java.toast(`\n用户：${username}\n注册并登录成功！\n用户数据已打印至源日志`);
    } catch (e) {
        java.log(e.message);
        java.toast('请求失败，请检查网络状况！');
    }
}

