        /* 深色模式切换按钮 */
        .theme-toggle {
            width: 36px;
            height: 36px;
            border-radius: 50%;
            border: none;
            background: #f5f5f5;
            color: #666;
            font-size: 16px;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
            margin-left: 12px;
        }

        .theme-toggle:hover {
            background: #eee;
        }

        .dark .theme-toggle {
            background: #3d3d3d;
            color: #ffc107;
        }

        .dark .theme-toggle:hover {
            background: #4d4d4d;
        }

        /* ==================== PC端响应式优化 ==================== */
        @media (min-width: 768px) {
            body {
                background: #e8e8e8;
            }

            .dark body,
