            .comment-main {
                gap: 16px;
            }

            .comment-username {
                font-size: 15px;
            }

            .comment-content {
                font-size: 15px;
                line-height: 1.7;
            }

            .comment-image {
                max-width: 300px;
                max-height: 300px;
            }

            .expand-replies {
                padding-left: 64px;
