            .reply-list {
                padding-left: 64px;
            }

            .reply-avatar img,
            .default-avatar.small {
                width: 32px;
                height: 32px;
                font-size: 14px;
            }

            .reply-main {
                gap: 12px;
            }

            .reply-username {
                font-size: 14px;
            }

            .reply-content {
                font-size: 14px;
                line-height: 1.6;
            }

            .bottom-bar {
                max-width: 800px;
                left: 50%;
                transform: translateX(-50%);
                border-radius: 12px 12px 0 0;
                box-shadow: 0 -2px 12px rgba(0,0,0,0.08);
            }

            .modal-content {
                max-width: 600px;
                margin: 0 auto;
                border-radius: 16px;
                margin-bottom: 20px;
            }

            /* 更多评论区域 */
            #moreSection {
                margin: 16px 0;
            }

            /* 加载状态 */
            .loading,
            .empty {
                background: #fff;
                border-radius: 12px;
                margin: 16px 0;
            }

            .dark .loading,
            .dark .empty {
                background: #2d2d2d;
            }

            .no-more {
                padding: 30px;
            }

            /* 列表容器 */
            .main-container > div[style*="margin: 0 12px"] {
                margin: 0 !important;
            }
